{"file_text": "@page "/chat"
@layout ChatLayout
@using sv_d46df4b3dbf9460689c54040b2ca8041.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<div class="chat-container">
    @* ── Left Sidebar: Channel List ── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @if (_channels is not null)
            {
                @foreach (var channel in _channels)
                {
                    <li class="channel-item @(channel.Id == _activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(channel)">
                        <div class="channel-name"># @channel.Name</div>
                        <div class="channel-desc">@TruncateDescription(channel.Description)</div>
                        @if (channel.UnreadCount > 0)
                        {
                            <span class="unread-badge">@channel.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* ── Main Message Area ── *@
    <section class="message-area @(_threadOpen ? "thread-open" : "")">
        @if (_activeChannel is not null)
        {
            <div class="message-header">
                <h2># @_activeChannel.Name</h2>
                <span class="channel-description">@_activeChannel.Description</span>
            </div>

            <div class="message-list" @onscroll="OnMessageScrollAsync">
                @if (_loadingOlder)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (_messages is not null)
                {
                    @foreach (var msg in _messages)
                    {
                        <div class="message-row" @onmouseenter="() => _hoveredMessageId = msg.Id"
                             @onmouseleave="() => _hoveredMessageId = null">
                            <div class="message-content-wrapper">
                                <div class="message-meta">
                                    <strong class="author">@msg.Author</strong>
                                    <span class="timestamp">@FormatRelativeTime(msg.SentAt)</span>
                                </div>
                                <div class="message-body">@msg.Content</div>

                                @if (msg.Reactions.Count > 0)
                                {
                                    <div class="reaction-row">
                                        @foreach (var reaction in msg.Reactions)
                                        {
                                            <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                                                @reaction.Emoji @reaction.Users.Count
                                            </span>
                                        }
                                    </div>
                                }

                                @{ var summary = GetThreadSummary(msg.Id); }
                                @if (summary is not null)
                                {
                                    <button class="thread-link" @onclick="() => OpenThreadAsync(msg.Id)">
                                        @summary.ReplyCount @(summary.ReplyCount == 1 ? "reply" : "replies")
                                        — last @FormatRelativeTime(summary.LastReplyAt)
                                    </button>
                                }
                            </div>

                            @if (_hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" title="Reply in thread"
                                            @onclick="() => OpenThreadAsync(msg.Id)">
                                        💬 Reply
                                    </button>
                                    <div class="emoji-picker-wrapper">
                                        <button class="action-btn" title="Add reaction"
                                                @onclick="() => ToggleEmojiPicker(msg.Id)">
                                            😀 React
                                        </button>
                                        @if (_emojiPickerMessageId == msg.Id)
                                        {
                                            <div class="emoji-picker">
                                                @foreach (var emoji in _commonEmojis)
                                                {
                                                    <button class="emoji-option"
                                                            @onclick="() => AddReactionAsync(msg.Id, emoji)">
                                                        @emoji
                                                    </button>
                                                }
                                            </div>
                                        }
                                    </div>
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-input" rows="2"
                          placeholder="Message #@_activeChannel.Name"
                          @bind="_newMessageText" @bind:event="oninput"
                          @onkeydown="OnMainInputKeyDownAsync" />
                <button class="send-btn" @onclick="SendMessageAsync"
                        disabled="@string.IsNullOrWhiteSpace(_newMessageText)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ── Right Panel: Thread View ── *@
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-thread-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </div>

            <div class="thread-root-quote">
                <div class="message-meta">
                    <strong class="author">@_threadRootMessage.Author</strong>
                    <span class="timestamp">@FormatRelativeTime(_threadRootMessage.SentAt)</span>
                </div>
                <div class="message-body">@_threadRootMessage.Content</div>
            </div>

            <div class="thread-replies">
                @if (_threadMessages is not null)
                {
                    @foreach (var reply in _threadMessages)
                    {
                        <div class="message-row thread-reply">
                            <div class="message-content-wrapper">
                                <div class="message-meta">
                                    <strong class="author">@reply.Author</strong>
                                    <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                                </div>
                                <div class="message-body">@reply.Content</div>

                                @if (reply.Reactions.Count > 0)
                                {
                                    <div class="reaction-row">
                                        @foreach (var reaction in reply.Reactions)
                                        {
                                            <span class="reaction-badge"
                                                  title="@string.Join(", ", reaction.Users)">
                                                @reaction.Emoji @reaction.Users.Count
                                            </span>
                                        }
                                    </div>
                                }
                            </div>
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-input" rows="2"
                          placeholder="Reply…"
                          @bind="_threadReplyText" @bind:event="oninput"
                          @onkeydown="OnThreadInputKeyDownAsync" />
                <button class="send-btn" @onclick="SendThreadReplyAsync"
                        disabled="@string.IsNullOrWhiteSpace(_threadReplyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    // ── Common emoji set for the quick-react picker ──
    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "😮", "👀"];

    // ── Channels ──
    private List<Channel>? _channels;
    private Channel? _activeChannel;
    private int? _activeChannelId;

    // ── Messages ──
    private List<Message>? _messages;
    private string _newMessageText = string.Empty;
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;
    private bool _loadingOlder;
    private bool _allOlderLoaded;
    private const int PageSize = 30;

    // ── Thread summaries (keyed by root message id) ──
    private Dictionary<int, ThreadSummary> _threadSummaries = new();

    // ── Thread panel ──
    private bool _threadOpen;
    private int? _threadRootId;
    private Message? _threadRootMessage;
    private List<Message>? _threadMessages;
    private string _threadReplyText = string.Empty;

    // ── Lifecycle ──

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
    }

    // ── Channel selection ──

    private async Task SelectChannelAsync(Channel channel)
    {
        if (channel.Id == _activeChannelId) return;

        _activeChannel = channel;
        _activeChannelId = channel.Id;
        _messages = null;
        _allOlderLoaded = false;
        _threadSummaries.Clear();
        CloseThread();

        var msgs = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _messages = msgs;

        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channel.Id);
        UpdateChannelUnreadCount(channel.Id);
    }

    private void UpdateChannelUnreadCount(int channelId)
    {
        if (_channels is null) return;
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            var c = _channels[idx];
            _channels[idx] = c with { UnreadCount = 0 };
        }
    }

    // ── Message pagination (load older on scroll-to-top) ──

    private async Task OnMessageScrollAsync(EventArgs e)
    {
        // JS interop-free: this fires on every scroll event.
        // The actual scroll-position check requires JS; we provide a manual trigger via
        // the "Loading older messages" indicator at the top. For a production app you'd
        // add a tiny JS interop to detect scrollTop === 0. Here we expose LoadOlderAsync
        // and also auto-trigger once if the list is short enough to already be at the top.
        await LoadOlderAsync();
    }

    private async Task LoadOlderAsync()
    {
        if (_loadingOlder || _allOlderLoaded || _messages is null || _activeChannelId is null)
            return;

        _loadingOlder = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _messages.Count, PageSize);
        if (older.Count == 0)
        {
            _allOlderLoaded = true;
        }
        else
        {
            _messages.AddRange(older);
            BuildThreadSummaries();
        }

        _loadingOlder = false;
    }

    // ── Send message ──

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessageText) || _activeChannelId is null) return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessageText.Trim(), null);
        _messages ??= new();
        _messages.Insert(0, sent);
        _newMessageText = string.Empty;
    }

    private async Task OnMainInputKeyDownAsync(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    // ── Reactions ──

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        _emojiPickerMessageId = null;
        await ChatService.AddReactionAsync(messageId, emoji);

        // Optimistic: update local message reaction list
        var msg = _messages?.FirstOrDefault(m => m.Id == messageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
            if (existing is not null)
            {
                if (!existing.Users.Contains("You"))
                    existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(emoji, new List<string> { "You" }));
            }
        }
    }

    // ── Thread helpers ──

    private void BuildThreadSummaries()
    {
        if (_messages is null) return;

        // Group replies by their ReplyToId to build summaries
        var replies = _messages.Where(m => m.ReplyToId is not null).ToList();
        var grouped = replies.GroupBy(m => m.ReplyToId!.Value);

        _threadSummaries.Clear();
        foreach (var g in grouped)
        {
            _threadSummaries[g.Key] = new ThreadSummary(
                g.Key,
                g.Count(),
                g.Max(m => m.SentAt)
            );
        }
    }

    private ThreadSummary? GetThreadSummary(int messageId)
    {
        return _threadSummaries.GetValueOrDefault(messageId);
    }

    // ── Thread panel ──

    private async Task OpenThreadAsync(int rootMessageId)
    {
        _threadRootId = rootMessageId;
        _threadRootMessage = _messages?.FirstOrDefault(m => m.Id == rootMessageId);
        _threadReplyText = string.Empty;
        _threadOpen = true;

        _threadMessages = await ChatService.GetThreadAsync(rootMessageId);
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootId = null;
        _threadRootMessage = null;
        _threadMessages = null;
        _threadReplyText = string.Empty;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReplyText) || _threadRootId is null || _activeChannelId is null)
            return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, _threadReplyText.Trim(), _threadRootId);
        _threadMessages ??= new();
        _threadMessages.Add(reply);

        // Also add to main messages list so thread summary updates
        _messages?.Insert(0, reply);
        BuildThreadSummaries();

        _threadReplyText = string.Empty;
    }

    private async Task OnThreadInputKeyDownAsync(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Formatting helpers ──

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string TruncateDescription(string description)
    {
        return description.Length > 40 ? description[..37] + "…" : description;
    }
}
