{"file_text": "/* ── Root container: three-panel flex layout ── */

.chat-container {
    display: flex;
    height: 100vh;
    width: 100vw;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    color: #1d1c1d;
    background: #fff;
}

/* ── Left Sidebar ── */

.channel-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    background: #3f0e40;
    color: #cfc3cf;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #522653;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid #522653;
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1.1rem;
    color: #fff;
    font-weight: 700;
}

.channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    padding: 6px 16px;
    cursor: pointer;
    border-radius: 6px;
    margin: 0 8px;
    transition: background-color 0.12s;
    position: relative;
}

.channel-item:hover {
    background: #4a154b;
}

.channel-item.active {
    background: #1164a3;
    color: #fff;
}

.channel-item.active .channel-desc {
    color: #d0e8f7;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    flex: 1;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-desc {
    width: 100%;
    font-size: 0.75rem;
    color: #ab9bab;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 1px;
}

.unread-badge {
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    min-width: 18px;
    height: 18px;
    line-height: 18px;
    text-align: center;
    border-radius: 9px;
    padding: 0 5px;
    position: absolute;
    right: 10px;
    top: 8px;
}

/* ── Main Message Area ── */

.message-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
    background: #fff;
}

.message-area.thread-open {
    /* shrinks when thread panel is visible */
}

.message-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e8e8e8;
    flex-shrink: 0;
}

.message-header h2 {
    margin: 0;
    font-size: 1.15rem;
    font-weight: 700;
}

.channel-description {
    font-size: 0.85rem;
    color: #616061;
}

.no-channel-selected {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #999;
    font-size: 1.1rem;
}

/* ── Message List ── */

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
    display: flex;
    flex-direction: column;
}

.loading-indicator {
    text-align: center;
    padding: 8px;
    color: #999;
    font-size: 0.85rem;
}

.message-row {
    display: flex;
    align-items: flex-start;
