    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-size: 0.95rem;
    color: #1d1c1d;
}

.timestamp {
    font-size: 0.75rem;
    color: #999;
}

.message-body {
    font-size: 0.93rem;
    line-height: 1.45;
    word-break: break-word;
