}

.message-input:focus {
    border-color: #1264a3;
}

.send-btn {
    background: #007a5a;
    color: #fff;
    border: none;
    border-radius: 8px;
    padding: 8px 20px;
    font-size: 0.9rem;
    font-weight: 600;
    cursor: pointer;
    white-space: nowrap;
    transition: background-color 0.12s;
}

.send-btn:hover:not(:disabled) {
    background: #006048;
}

.send-btn:disabled {
    background: #ccc;
    cursor: default;
}

/* ── Right Panel: Thread View ── */

.thread-panel {
    width: 25%;
    min-width: 280px;
