    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1.05rem;
    font-weight: 700;
}

.close-thread-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    color: #666;
    padding: 2px 6px;
    border-radius: 4px;
    line-height: 1;
