.close-thread-btn:hover {
    background: #f0f0f0;
    color: #111;
}

.thread-root-quote {
    padding: 12px 16px;
    background: #f8f8f8;
    border-bottom: 1px solid #e8e8e8;
    flex-shrink: 0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.thread-reply {
    padding: 6px 16px;
}

.thread-panel .message-input-area {
    padding: 12px 16px;
}
