+    private bool _threadOpen;
+    private int? _threadRootId;
+    private Message? _threadRootMessage;
+    private List<Message>? _threadMessages;
+    private string _threadReplyText = string.Empty;
+
+    // ── Lifecycle ──
+
+    protected override async Task OnInitializedAsync()
+    {
+        _channels = await ChatService.GetChannelsAsync();
+    }
+
+    // ── Channel selection ──
+
+    private async Task SelectChannelAsync(Channel channel)
+    {
+        if (channel.Id == _activeChannelId) return;
+
+        _activeChannel = channel;
+        _activeChannelId = channel.Id;
+        _messages = null;
+        _allOlderLoaded = false;
+        _threadSummaries.Clear();
+        CloseThread();
+
+        var msgs = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
+        _messages = msgs;
+
+        BuildThreadSummaries();
+
+        await ChatService.MarkChannelReadAsync(channel.Id);
+        UpdateChannelUnreadCount(channel.Id);
+    }
+
+    private void UpdateChannelUnreadCount(int channelId)
+    {
+        if (_channels is null) return;
+        var idx = _channels.FindIndex(c => c.Id == channelId);
+        if (idx >= 0)
+        {
+            var c = _channels[idx];
+            _channels[idx] = c with { UnreadCount = 0 };
+        }
+    }
+
+    // ── Message pagination (load older on scroll-to-top) ──
+
+    private async Task OnMessageScrollAsync(EventArgs e)
+    {
+        // JS interop-free: this fires on every scroll event.
+        // The actual scroll-position check requires JS; we provide a manual trigger via
+        // the "Loading older messages" indicator at the top. For a production app you'd
+        // add a tiny JS interop to detect scrollTop === 0. Here we expose LoadOlderAsync
+        // and also auto-trigger once if the list is short enough to already be at the top.
+        await LoadOlderAsync();
+    }
+
+    private async Task LoadOlderAsync()
+    {
+        if (_loadingOlder || _allOlderLoaded || _messages is null || _activeChannelId is null)
+            return;
+
+        _loadingOlder = true;
+        StateHasChanged();
+
+        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _messages.Count, PageSize);
+        if (older.Count == 0)
+        {
+            _allOlderLoaded = true;
+        }
+        else
+        {
+            _messages.AddRange(older);
+            BuildThreadSummaries();
+        }
+
+        _loadingOlder = false;
+    }
+
+    // ── Send message ──
+
+    private async Task SendMessageAsync()
+    {
+        if (string.IsNullOrWhiteSpace(_newMessageText) || _activeChannelId is null) return;
+
+        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessageText.Trim(), null);
+        _messages ??= new();
+        _messages.Insert(0, sent);
+        _newMessageText = string.Empty;
+    }
+
+    private async Task OnMainInputKeyDownAsync(KeyboardEventArgs e)
+    {
+        if (e is { Key: "Enter", ShiftKey: false })
+        {
+            await SendMessageAsync();
+        }
+    }
+
+    // ── Reactions ──
+
+    private void ToggleEmojiPicker(int messageId)
+    {
+        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
+    }
+
+    private async Task AddReactionAsync(int messageId, string emoji)
+    {
+        _emojiPickerMessageId = null;
+        await ChatService.AddReactionAsync(messageId, emoji);
+
+        // Optimistic: update local message reaction list
+        var msg = _messages?.FirstOrDefault(m => m.Id == messageId);
+        if (msg is not null)
+        {
+            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
+            if (existing is not null)
+            {
+                if (!existing.Users.Contains("You"))
+                    existing.Users.Add("You");
+            }
+            else
+            {
+                msg.Reactions.Add(new Reaction(emoji, new List<string> { "You" }));
+            }
+        }
+    }
+
+    // ── Thread helpers ──
+
+    private void BuildThreadSummaries()
+    {
+        if (_messages is null) return;
+
+        // Group replies by their ReplyToId to build summaries
+        var replies = _messages.Where(m => m.ReplyToId is not null).ToList();
+        var grouped = replies.GroupBy(m => m.ReplyToId!.Value);
+
+        _threadSummaries.Clear();
+        foreach (var g in grouped)
+        {
+            _threadSummaries[g.Key] = new ThreadSummary(
+                g.Key,
+                g.Count(),
+                g.Max(m => m.SentAt)
+            );
+        }
+    }
+
+    private ThreadSummary? GetThreadSummary(int messageId)
+    {
+        return _threadSummaries.GetValueOrDefault(messageId);
+    }
+
+    // ── Thread panel ──
+
+    private async Task OpenThreadAsync(int rootMessageId)
+    {
+        _threadRootId = rootMessageId;
+        _threadRootMessage = _messages?.FirstOrDefault(m => m.Id == rootMessageId);
+        _threadReplyText = string.Empty;
+        _threadOpen = true;
+
+        _threadMessages = await ChatService.GetThreadAsync(rootMessageId);
+    }
+
+    private void CloseThread()
+    {
+        _threadOpen = false;
+        _threadRootId = null;
+        _threadRootMessage = null;
+        _threadMessages = null;
+        _threadReplyText = string.Empty;
+    }
+
+    private async Task SendThreadReplyAsync()
+    {
+        if (string.IsNullOrWhiteSpace(_threadReplyText) || _threadRootId is null || _activeChannelId is null)
+            return;
+
+        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, _threadReplyText.Trim(), _threadRootId);
+        _threadMessages ??= new();
+        _threadMessages.Add(reply);
+
+        // Also add to main messages list so thread summary updates
+        _messages?.Insert(0, reply);
+        BuildThreadSummaries();
+
+        _threadReplyText = string.Empty;
+    }
+
+    private async Task OnThreadInputKeyDownAsync(KeyboardEventArgs e)
+    {
+        if (e is { Key: "Enter", ShiftKey: false })
+        {
+            await SendThreadReplyAsync();
+        }
+    }
+
+    // ── Formatting helpers ──
+
+    private static string FormatRelativeTime(DateTime sentAt)
+    {
+        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
+        return diff.TotalSeconds switch
+        {
+            < 60 => "just now",
+            < 3600 => $"{(int)diff.TotalMinutes} min ago",
+            < 86400 => $"{(int)diff.TotalHours}h ago",
+            < 604800 => $"{(int)diff.TotalDays}d ago",
+            _ => sentAt.ToString("MMM d, yyyy")
+        };
+    }
+
+    private static string TruncateDescription(string description)
+    {
+        return description.Length > 40 ? description[..37] + "…" : description;
+    }
+}
+

